Can't you just have a z pointer that goes through each element In the array and an i and j pointer that multiplies all elements before z and after z? That's the solution I came up with and it looks like this:

class Solution:
    def productExceptSelf(self, nums: List[int]) -> List[int]:
        output = []

        for z in range(len(nums)):
            product = 1
            for i in range(z + 1, len(nums)):
                product *= nums[i]
            for j in range(z - 1, -1, -1):
                product *= nums[j]
            output.append(product)

        return output

