I used dfs, with cache:

def solution(root):
    cache = {}
    return helper(root, cache, 1)


def helper(root, cache, l):
    if not root:
        return []

    if l not in cache:
        cache[l] = [root.val]
    else:
        cache[l].append(root.val)

    helper(root.left, cache, l+1)
    helper(root.right, cache, l + 1)
    return list(cache.values())

