## Top down memoization solution


class Solution:
    def __init__(self):
        self.hmap={}



    def climbStairs(self, n: int) -> int:

        return self.jump(0,n)

        #return self.result


    def jump(self,step,n):

        ## Base
        if step==n:
            #self.result+=1
            return 1

        if step>n:
            return 0

        ## logic
        res=0
        # jump 1 step
        for i in range(1,3):
            newstep=step+i
            if step not in self.hmap:
                temp=self.jump(newstep,n)
                self.hmap[newstep]=temp
            #else:
            res += self.hmap[newstep]


        return res
